typedef float fp;

#define MAX_LOCAL_SIZE 1024

__kernel void extract_kernel(long d_Ne,
                             __global fp *d_I)
{
    long ei = (long)get_global_id(0);

    if (ei < d_Ne) {
        d_I[ei] = exp(d_I[ei] / 255.0f);
    }
}

__kernel void prepare_kernel(long d_Ne,
                             __global fp *d_I,
                             __global fp *d_sums,
                             __global fp *d_sums2)
{
    long ei = (long)get_global_id(0);

    if (ei < d_Ne) {
        d_sums[ei] = d_I[ei];
        d_sums2[ei] = d_I[ei] * d_I[ei];
    }
}

__kernel void reduce_kernel(long d_Ne,
                            long d_no,
                            int d_mul,
                            __global fp *d_sums,
                            __global fp *d_sums2,
                            int d_blocks)
{
    int bx = (int)get_group_id(0);
    int tx = (int)get_local_id(0);
    int local_size = (int)get_local_size(0);
    int num_groups = (int)get_num_groups(0);
    long ei = (long)bx * (long)local_size + (long)tx;
    int nf = local_size - (num_groups * local_size - (int)d_no);
    int df = 0;
    int i;

    __local fp d_psum[MAX_LOCAL_SIZE];
    __local fp d_psum2[MAX_LOCAL_SIZE];

    if (tx < MAX_LOCAL_SIZE) {
        d_psum[tx] = 0.0f;
        d_psum2[tx] = 0.0f;
    }

    if (ei < d_no) {
        d_psum[tx] = d_sums[ei * (long)d_mul];
        d_psum2[tx] = d_sums2[ei * (long)d_mul];
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    if (nf == local_size) {

        for (i = 2; i <= local_size; i = 2 * i) {

            if (((tx + 1) % i) == 0) {
                d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
            }

            barrier(CLK_LOCAL_MEM_FENCE);
        }

        if (tx == (local_size - 1)) {
            d_sums[(long)bx * (long)d_mul * (long)local_size] = d_psum[tx];
            d_sums2[(long)bx * (long)d_mul * (long)local_size] = d_psum2[tx];
        }
    }
    else {

        if (bx != (num_groups - 1)) {

            for (i = 2; i <= local_size; i = 2 * i) {

                if (((tx + 1) % i) == 0) {
                    d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                    d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                }

                barrier(CLK_LOCAL_MEM_FENCE);
            }

            if (tx == (local_size - 1)) {
                d_sums[(long)bx * (long)d_mul * (long)local_size] = d_psum[tx];
                d_sums2[(long)bx * (long)d_mul * (long)local_size] = d_psum2[tx];
            }
        }
        else {

            for (i = 2; i <= local_size; i = 2 * i) {
                if (nf >= i) {
                    df = i;
                }
            }

            for (i = 2; i <= df; i = 2 * i) {

                if (((tx + 1) % i) == 0 && tx < df) {
                    d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                    d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                }

                barrier(CLK_LOCAL_MEM_FENCE);
            }

            if (tx == (df - 1)) {

                for (i = bx * local_size + df; i < bx * local_size + nf; i++) {
                    d_psum[tx] = d_psum[tx] + d_sums[i];
                    d_psum2[tx] = d_psum2[tx] + d_sums2[i];
                }

                d_sums[(long)bx * (long)d_mul * (long)local_size] = d_psum[tx];
                d_sums2[(long)bx * (long)d_mul * (long)local_size] = d_psum2[tx];
            }
        }
    }
}

__kernel void srad_kernel(fp d_lambda,
                          int d_Nr,
                          int d_Nc,
                          long d_Ne,
                          __global int *d_iN,
                          __global int *d_iS,
                          __global int *d_jE,
                          __global int *d_jW,
                          __global fp *d_dN,
                          __global fp *d_dS,
                          __global fp *d_dW,
                          __global fp *d_dE,
                          fp d_q0sqr,
                          __global fp *d_c,
                          __global fp *d_I)
{
    long ei = (long)get_global_id(0);

    if (ei < d_Ne) {
        int row = (int)(ei % (long)d_Nr);
        int col = (int)(ei / (long)d_Nr);

        fp Jc = d_I[ei];
        fp dN = d_I[(long)d_iN[row] + (long)d_Nr * (long)col] - Jc;
        fp dS = d_I[(long)d_iS[row] + (long)d_Nr * (long)col] - Jc;
        fp dW = d_I[(long)row + (long)d_Nr * (long)d_jW[col]] - Jc;
        fp dE = d_I[(long)row + (long)d_Nr * (long)d_jE[col]] - Jc;

        fp G2 = (dN * dN + dS * dS + dW * dW + dE * dE) / (Jc * Jc);
        fp L = (dN + dS + dW + dE) / Jc;
        fp num = (0.5f * G2) - ((1.0f / 16.0f) * (L * L));
        fp den = 1.0f + (0.25f * L);
        fp qsqr = num / (den * den);
        fp c;

        den = (qsqr - d_q0sqr) / (d_q0sqr * (1.0f + d_q0sqr));
        c = 1.0f / (1.0f + den);

        if (c < 0.0f) {
            c = 0.0f;
        }
        else if (c > 1.0f) {
            c = 1.0f;
        }

        d_dN[ei] = dN;
        d_dS[ei] = dS;
        d_dW[ei] = dW;
        d_dE[ei] = dE;
        d_c[ei] = c;
    }
}

__kernel void srad2_kernel(fp d_lambda,
                           int d_Nr,
                           int d_Nc,
                           long d_Ne,
                           __global int *d_iN,
                           __global int *d_iS,
                           __global int *d_jE,
                           __global int *d_jW,
                           __global fp *d_dN,
                           __global fp *d_dS,
                           __global fp *d_dW,
                           __global fp *d_dE,
                           __global fp *d_c,
                           __global fp *d_I)
{
    long ei = (long)get_global_id(0);

    if (ei < d_Ne) {
        int row = (int)(ei % (long)d_Nr);
        int col = (int)(ei / (long)d_Nr);

        fp cN = d_c[ei];
        fp cS = d_c[(long)d_iS[row] + (long)d_Nr * (long)col];
        fp cW = d_c[ei];
        fp cE = d_c[(long)row + (long)d_Nr * (long)d_jE[col]];
        fp D = cN * d_dN[ei] + cS * d_dS[ei] + cW * d_dW[ei] + cE * d_dE[ei];

        d_I[ei] = d_I[ei] + 0.25f * d_lambda * D;
    }
}

__kernel void compress_kernel(long d_Ne,
                              __global fp *d_I)
{
    long ei = (long)get_global_id(0);

    if (ei < d_Ne) {
        d_I[ei] = log(d_I[ei]) * 255.0f;
    }
}
